mapper.select:
SELECT id, property_type, name, sgg_cd, umd_nm, jibun, build_year, latitude, longitude, latest_sale_price, latest_deposit, latest_monthly_rent FROM property
AND sgg_cd = #{sggCd}
AND umd_nm = #{umdNm}
AND name LIKE CONCAT('%', #{name}, '%')
AND property_type = #{propertyType}
AND latest_sale_price > 0
AND latest_sale_price >= #{minPrice}
AND latest_sale_price <= #{maxPrice}
AND latest_deposit > 0 AND latest_monthly_rent = 0
AND latest_deposit >= #{minPrice}
AND latest_deposit <= #{maxPrice}
AND latest_monthly_rent > 0
AND latest_deposit >= #{minPrice}
AND latest_deposit <= #{maxPrice}
AND ( latest_sale_price >= #{minPrice} OR latest_deposit >= #{minPrice} )
AND ( (latest_sale_price > 0 AND latest_sale_price <= #{maxPrice}) OR (latest_deposit > 0 AND latest_deposit <= #{maxPrice}) )
ORDER BY
latest_sale_price
latest_deposit
GREATEST(latest_sale_price, latest_deposit)
name
updated_at
ASC
DESC
, id DESC

SELECT id, latitude, longitude
FROM property
WHERE property_type = #{propertyType}
  AND sgg_cd = #{sggCd}
  AND umd_nm = #{umdNm}
  AND jibun = #{jibun}
  AND name = #{name}
  AND build_year = #{buildYear}

mapper.update:
UPDATE property
SET latitude = #{latitude},
    longitude = #{longitude}
WHERE id = #{id}

mapper.insert:
INSERT IGNORE INTO sale_deal (
  property_id, exclusive_area, land_area, deal_amount, floor,
  deal_date, buyer_gbn, seller_gbn
) VALUES (
  #{propertyId}, #{exclusiveArea}, #{landArea}, #{dealAmount}, #{floor},
  #{dealDate}, #{buyerGbn}, #{sellerGbn}
)

INSERT IGNORE INTO rent_deal (
  property_id, exclusive_area, land_area, deposit, monthly_rent, floor,
  contract_term, contract_type, use_rr_right, pre_deposit, pre_monthly_rent, deal_date
) VALUES (
  #{propertyId}, #{exclusiveArea}, #{landArea}, #{deposit}, #{monthlyRent}, #{floor},
  #{contractTerm}, #{contractType}, #{useRrRight}, #{preDeposit}, #{preMonthlyRent}, #{dealDate}
)

mapper.update:
UPDATE property
SET latest_sale_price = #{dealAmount}
WHERE id = #{propertyId}
  AND NOT EXISTS (
    SELECT 1
    FROM sale_deal newer
    WHERE newer.property_id = #{propertyId}
      AND newer.deal_date > #{dealDate}
  )

UPDATE property
SET latest_deposit = #{deposit},
    latest_monthly_rent = #{monthlyRent}
WHERE id = #{propertyId}
  AND NOT EXISTS (
    SELECT 1
    FROM rent_deal newer
    WHERE newer.property_id = #{propertyId}
      AND newer.deal_date > #{dealDate}
  )
